// Parse + validate LinkedIn Ad / Creative Performance export -> fact rows (SNAPSHOT ingest).
// CHANGES vs original daily-export version:
//   1. BOM-aware decode: handles UTF-16 LE/BE *and* UTF-8 (LinkedIn UI exports are UTF-16).
//   2. Snapshot semantics: this export is a lifetime-to-date aggregate with NO per-day rows
//      (every row's "Start Date (in UTC)" = the report's start date). We therefore stamp
//      activity_date from the report's "Date Generated" preamble line, NOT the row date.
//   3. Skips the multi-line preamble and auto-detects the header row.
// Rejects the whole file with a clear error if required metric columns are missing (T-3 AC).

// ---- 1. Decode bytes (BOM-aware). Falls back to upstream text if no binary present. ----
function decodeBuf(buf) {
  if (!buf || !buf.length) return '';
  if (buf[0] === 0xFF && buf[1] === 0xFE) return buf.toString('utf16le');        // UTF-16 LE
  if (buf[0] === 0xFE && buf[1] === 0xFF) {                                       // UTF-16 BE -> byte-swap
    const s = Buffer.alloc(buf.length);
    for (let i = 0; i + 1 < buf.length; i += 2) { s[i] = buf[i + 1]; s[i + 1] = buf[i]; }
    return s.toString('utf16le');
  }
  return buf.toString('utf8');
}
let text;
try {
  const buf = await this.helpers.getBinaryDataBuffer(0, 'data');
  text = decodeBuf(buf);
} catch (e) {
  text = String($input.first().json.data || '');
}
text = text.replace(/^\uFEFF/, '');
if (text.indexOf('\x00') >= 0) text = text.replace(/\x00/g, ''); // scrub stray nulls if any slipped through

// ---- 2. Snapshot date from the report preamble ----
function toISOlong(s) { const t = Date.parse(s); return isNaN(t) ? null : new Date(t).toISOString().slice(0, 10); }
function snapshotDate(t) {
  let m = t.match(/Date Generated:\s*([A-Za-z]+ \d{1,2},\s*\d{4})/i);
  if (!m) m = t.match(/Report End:\s*([A-Za-z]+ \d{1,2},\s*\d{4})/i);
  if (m) { const iso = toISOlong(m[1]); if (iso) return iso; }
  return new Date().toISOString().slice(0, 10); // last-resort fallback
}
const snapDate = snapshotDate(text);

// ---- 3. CSV/TSV parse (quoted, multi-line safe) ----
function parseCSV(t, delim) {
  const rows = []; let row = []; let cur = ''; let inQ = false;
  for (let i = 0; i < t.length; i++) {
    const ch = t[i];
    if (inQ) {
      if (ch === '"') { if (t[i + 1] === '"') { cur += '"'; i++; } else { inQ = false; } }
      else { cur += ch; }
    } else if (ch === '"') { inQ = true; }
    else if (ch === delim) { row.push(cur); cur = ''; }
    else if (ch === '\n') { row.push(cur); rows.push(row); row = []; cur = ''; }
    else if (ch === '\r') { /* skip */ }
    else { cur += ch; }
  }
  if (cur.length || row.length) { row.push(cur); rows.push(row); }
  return rows;
}
const delim = text.indexOf('\t') >= 0 ? '\t' : ','; // LinkedIn UI export is tab-delimited
const all = parseCSV(text, delim).filter((r) => r.some((c) => String(c).trim() !== ''));

const norm = (s) => String(s || '').toLowerCase().replace(/[^a-z0-9 ]/g, ' ').replace(/ +/g, ' ').trim();
let hIdx = -1;
for (let i = 0; i < Math.min(all.length, 15); i++) {
  const h = all[i].map(norm);
  if (h.some((c) => c.indexOf('campaign name') >= 0) && h.some((c) => c.indexOf('impressions') >= 0)) { hIdx = i; break; }
}
if (hIdx < 0) {
  throw new Error('LinkedIn CSV rejected - header row not found (expected Campaign Name + Impressions columns). Check the export is a LinkedIn Ad/Campaign performance report.');
}
const headers = all[hIdx].map(norm);
function col() {
  for (let n = 0; n < arguments.length; n++) {
    const want = arguments[n];
    let i = headers.findIndex((h) => h === want);
    if (i < 0) i = headers.findIndex((h) => h.indexOf(want) >= 0);
    if (i >= 0) return i;
  }
  return -1;
}
const iName = col('campaign name');
const iId = col('campaign id');
const iSpend = col('total spent', 'spent', 'cost');
const iImpr = col('impressions');
const iClicks = col('clicks');
const iLeads = col('leads');
const missing = [];
if (iName < 0) missing.push('Campaign Name');
if (iId < 0) missing.push('Campaign ID');
if (iSpend < 0) missing.push('Total Spent');
if (iImpr < 0) missing.push('Impressions');
if (iClicks < 0) missing.push('Clicks');
if (iLeads < 0) missing.push('Leads');
if (missing.length) {
  throw new Error('LinkedIn CSV rejected - missing required columns: ' + missing.join(', '));
}

function num(v) {
  const n = Number(String(v == null ? '' : v).replace(/[^0-9.\-]/g, ''));
  return isNaN(n) ? 0 : n;
}
function regionFromName(name) {
  const n = ' ' + String(name || '').toLowerCase() + ' ';
  if (/(belux|benelux|belgium|luxembourg)/.test(n)) return 'BeLux';
  if (/(netherlands|holland)/.test(n) || / nl /.test(n) || /[ _\-]nl[ _\-]/.test(n)) return 'NL';
  if (/(uki|uk i|uk and ireland|united kingdom|ireland)/.test(n) || / uk /.test(n) || /[ _\-]uk[ _\-]/.test(n)) return 'UKI';
  return 'UNASSIGNED'; // TODO(Margot/Fluoro): confirm region tokens used in campaign names
}

// ---- 4. Aggregate ad-level rows up to campaign x region (date is the constant snapshot date) ----
const agg = {};
let rowsIn = 0;
for (let i = hIdx + 1; i < all.length; i++) {
  const r = all[i];
  const nameNorm = norm(r[iName]);
  if (nameNorm.indexOf('total') === 0) continue; // totals footer
  if (!String(r[iId] || '').trim()) continue;    // blank / footer rows
  rowsIn++;
  const id = String(r[iId]).trim();
  const region = regionFromName(r[iName]);
  const key = id + '|' + region;
  if (!agg[key]) {
    agg[key] = { campaign_key: 'LI_' + id, campaign_name: String(r[iName] || '').trim(),
      region_code: region, channel_name: 'LinkedIn Paid', activity_date: snapDate,
      source: 'linkedin', spend: 0, impressions: 0, clicks: 0, leads: 0 };
  }
  const a = agg[key];
  a.spend += num(r[iSpend]);
  a.impressions += num(r[iImpr]);
  a.clicks += num(r[iClicks]);
  a.leads += num(r[iLeads]);
}

const out = Object.values(agg);
if (out.length === 0) {
  throw new Error('LinkedIn CSV rejected - no valid data rows after validation (rows in: ' + rowsIn + ')');
}
const meta = { rows_in: rowsIn, issues: 0, issue_pct: 0, snapshot_date: snapDate, report_type: 'lifetime_snapshot' };
return out.map((json) => ({ json: Object.assign({}, json, { _meta: meta }) }));

// Distinct campaigns for dim_campaign upsert.
const seen = {};
const out = [];
for (const item of $('Parse + Validate LinkedIn CSV').all()) {
  const j = item.json;
  if (seen[j.campaign_key]) continue;
  seen[j.campaign_key] = 1;
  out.push({ json: { campaign_key: j.campaign_key, campaign_name: j.campaign_name,
    channel_name: j.channel_name, source_system: 'linkedin' } });
}
return out;
